export function isRoundedIconFallbackSourceName(
	name: RoundedIconSourceName,
): name is RoundedIconFallbackSourceName {
	return roundedIconFallbackSourceNames.some(
		(fallbackName) => fallbackName === name,
	);
}

export function getRoundedIconFallbackData(
	name: RoundedIconSourceName,
): RoundedIconData {
	if (!isRoundedIconFallbackSourceName(name)) {
		throw new Error(`Rounded icon ${name} has no approved Acepe fallback geometry`);
	}
	return roundedIconData[name];
}

export const roundedIconAliasNames = [
	"bell",
	"browser",
	"files",
	"moon",
	"question",
	"settings-cog",
	"sidebar-closed",
	"three",
] as const;

export type RoundedIconAliasName = (typeof roundedIconAliasNames)[number];

export const roundedIconAliases: Record<RoundedIconAliasName, RoundedIconSourceName> = {
	"bell": "automations",
	"browser": "globe",
	"files": "folders",
	"moon": "gpu",
	"question": "question-circle",
	"settings-cog": "settings",
	"sidebar-closed": "sidebar",
	"three": "more",
};

export type RoundedIconName = RoundedIconSourceName | RoundedIconAliasName;

export function isRoundedIconAliasName(name: RoundedIconName): name is RoundedIconAliasName {
	return Object.hasOwn(roundedIconAliases, name);
}

export function resolveRoundedIconName(name: RoundedIconName): RoundedIconSourceName {
	if (isRoundedIconAliasName(name)) {
		return roundedIconAliases[name];
	}

	return name;
}
